function slug(string $name): string { $slug=strtolower(trim(preg_replace('/[^a-z0-9]+/i','-',iconv('UTF-8','ASCII//TRANSLIT',$name) ?: $name),'-')); return $slug?:'produk-'.bin2hex(random_bytes(3)); }
function installer_checks(): array { return [
    ['name'=>'PHP', 'value'=>PHP_VERSION.' (minimal 8.2)', 'ok'=>version_compare(PHP_VERSION,'8.2.0','>=')],
    ['name'=>'PDO MySQL', 'value'=>extension_loaded('pdo_mysql')?'Aktif':'Tidak aktif', 'ok'=>extension_loaded('pdo_mysql')],
    ['name'=>'OpenSSL', 'value'=>extension_loaded('openssl')?'Aktif':'Tidak aktif', 'ok'=>extension_loaded('openssl')],
    ['name'=>'Mbstring', 'value'=>extension_loaded('mbstring')?'Aktif':'Tidak aktif', 'ok'=>extension_loaded('mbstring')],
    ['name'=>'JSON', 'value'=>extension_loaded('json')?'Aktif':'Tidak aktif', 'ok'=>extension_loaded('json')],
    ['name'=>'storage/ dapat ditulis', 'value'=>is_writable(ROOT.'/storage')?'Writable':'Tidak writable', 'ok'=>is_dir(ROOT.'/storage') && is_writable(ROOT.'/storage')],
    ['name'=>'Root project dapat ditulis', 'value'=>is_writable(ROOT)?'Writable (.env dibuat di sini)':'Tidak writable', 'ok'=>is_writable(ROOT)],
    ['name'=>'Schema database', 'value'=>is_readable(ROOT.'/database/schema.sql')?'Terbaca':'Tidak terbaca', 'ok'=>is_readable(ROOT.'/database/schema.sql')],
]; }
function installer_ready(): bool { foreach(installer_checks() as $check)if(!$check['ok'])return false;return true; }
function installer_view(string $step,string $title,string $content): never { view('Installer','<section class="hero"><p class="type">Zenhosta setup · '.$step.'</p>'.$title.'</section><p class="muted">1. Pemeriksaan server · 2. Database · 3. Admin · 4. Lisensi</p>'.$content); }
function pakasir_mode_field(array $s): string { $mode=$s['pakasir_mode']??'sandbox';return '<label>Mode Pakasir<select name="pakasir_mode"><option value="sandbox" '.($mode==='sandbox'?'selected':'').'>Sandbox - testing pembayaran</option><option value="live" '.($mode==='live'?'selected':'').'>Live - menerima pembayaran</option></select></label><p class="muted">Gunakan mode yang sama dengan project di dashboard Pakasir. Endpoint tetap `app.pakasir.com`; mode Sandbox dapat memakai API `paymentsimulation` untuk menguji webhook.</p>'; }
function ensure_product_image_column(): void { static $done=false;if($done)return;$done=true;$exists=q("SELECT COUNT(*) FROM information_schema.columns WHERE table_schema=DATABASE() AND table_name='products' AND column_name='image_url'")->fetchColumn();if(!$exists)q('ALTER TABLE products ADD image_url TEXT NULL AFTER price'); }
function parse_stock_lines(string $input): ?array { $accounts=[];foreach(preg_split('/\R/',trim($input)) as $line){$line=trim($line);if($line==='')continue;$parts=explode('|',$line,2);if(count($parts)!==2||!filter_var(trim($parts[0]),FILTER_VALIDATE_EMAIL)||trim($parts[1])==='')return null;$accounts[]=trim($parts[0]).'|'.trim($parts[1]);}return $accounts; }
function valid_hex(string $value): ?string { return preg_match('/^#[0-9a-fA-F]{6}$/',$value)?$value:null; }
function save_appearance_image(string $field,string $current): string { $url=trim($_POST[$field.'_url']??'');if($url!==''&&valid_delivery_url($url))return $url;$file=$_FILES[$field.'_upload']??null;if(!$file||$file['error']===UPLOAD_ERR_NO_FILE)return $current;if($file['error']!==UPLOAD_ERR_OK||$file['size']>2*1024*1024)throw new RuntimeException('Upload gambar gagal atau melebihi 2 MB.');$mime=(new finfo(FILEINFO_MIME_TYPE))->file($file['tmp_name']);$ext=['image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp'][$mime]??null;if(!$ext)throw new RuntimeException('Gambar hanya boleh JPG, PNG, atau WEBP.');$name=bin2hex(random_bytes(16)).'.'.$ext;$target=ROOT.'/storage/uploads/'.$name;if(!move_uploaded_file($file['tmp_name'],$target))throw new RuntimeException('Gagal menyimpan gambar.');return '/media/'.$name; }
function appearance_page(array $s): string { return '<section class="hero"><p class="type">Brand dan halaman depan</p><h1>Tampilan toko.</h1><p class="muted">Atur identitas, warna, font, logo, dan hero kecil. Produk tetap terlihat setelah hero.</p></section><form method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="'.csrf().'\"><section class="form-section"><h2>Identitas</h2><label>Nama toko<input name="store_name" value="'.e($s['store_name']??'').'" required></label><label>Logo URL HTTPS<input name="store_logo_url" type="url" placeholder="https://..." value="'.e(str_starts_with($s['store_logo']??'','http')?$s['store_logo']:'').'\"></label><label>Atau upload logo<input name="store_logo_upload" type="file" accept="image/jpeg,image/png,image/webp"></label></section><section class="form-section"><h2>Warna dan font</h2><div class="form-grid"><label>Warna utama<input name="theme_primary" type="color" value="'.e($s['theme_primary']??'#17231e').'\"></label><label>Warna tombol<input name="theme_accent" type="color" value="'.e($s['theme_accent']??'#c8f45c').'\"></label><label>Background<input name="theme_background" type="color" value="'.e($s['theme_background']??'#f3f0e8').'\"></label><label>Font judul<select name="theme_font"><option value="fraunces" '.(($s['theme_font']??'')!=='serif'?'selected':'').'>Fraunces editorial</option><option value="serif" '.(($s['theme_font']??'')==='serif'?'selected':'').'>Serif klasik</option></select></label></div></section><section class="form-section"><h2>Hero ringkas</h2><label>Judul hero<input name="hero_title" value="'.e($s['hero_title']??'').'" placeholder="Produk digital siap kirim"></label><label>Subjudul hero<input name="hero_subtitle" value="'.e($s['hero_subtitle']??'').'" placeholder="Ebook, video, dan akun premium."></label><label>Banner URL HTTPS<input name="hero_banner_url" type="url" placeholder="https://..." value="'.e(str_starts_with($s['hero_banner']??'','http')?$s['hero_banner']:'').'\"></label><label>Atau upload banner<input name="hero_banner_upload" type="file" accept="image/jpeg,image/png,image/webp"></label></section><section class="form-section"><h2>Katalog</h2><label>Judul katalog<input name="catalog_heading" value="'.e($s['catalog_heading']??'Produk pilihan').'\"></label></section><button class="btn lime">Simpan tampilan</button> <a class="btn" href="'.base('/').'" target="_blank">Lihat toko</a></form>'; }
function appearance_page_v2(array $s): string { $primary=$s['theme_primary']??'#17231e';$accent=$s['theme_accent']??'#c8f45c';$background=$s['theme_background']??'#f3f0e8';$font=$s['theme_font']??'fraunces';return '<style>.theme-presets{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}.theme-preset{border:1px solid #aebcb3;border-radius:8px;padding:10px;background:#fffdf8;text-align:left;cursor:pointer}.theme-swatches{display:flex;gap:4px;margin-bottom:8px}.theme-swatches i{display:block;width:22px;height:22px;border-radius:50%;border:1px solid rgba(0,0,0,.15)}.theme-preview{padding:18px;border-radius:9px;margin-top:16px}.font-choice{display:flex;gap:10px;flex-wrap:wrap}.font-choice label{display:flex!important;align-items:center;gap:8px;padding:11px 13px;border:1px solid #aebcb3;border-radius:7px;background:#fffdf8}.font-choice input{width:auto!important;padding:0!important}@media(max-width:600px){.theme-presets{grid-template-columns:1fr}}</style><section class="hero"><p class="type">Brand dan halaman depan</p><h1>Tampilan toko.</h1><p class="muted">Atur identitas, tema, logo, dan hero kecil.</p></section><form method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="'.csrf().'"><section class="form-section"><h2>Identitas</h2><label>Nama toko<input name="store_name" value="'.e($s['store_name']??'').'" required></label><label>Logo URL HTTPS<input name="store_logo_url" type="url" placeholder="https://..." value="'.e(str_starts_with($s['store_logo']??'','http')?$s['store_logo']:'').'"></label><label>Atau upload logo<input name="store_logo_upload" type="file" accept="image/jpeg,image/png,image/webp"></label></section><section class="form-section"><h2>Warna dan font</h2><p class="muted">Pilih preset dulu, lalu sesuaikan warna bila perlu.</p><div class="theme-presets"><button class="theme-preset" type="button" onclick="setTheme(\'#17231e\',\'#c8f45c\',\'#f3f0e8\')"><span class="theme-swatches"><i style="background:#17231e"></i><i style="background:#c8f45c"></i><i style="background:#f3f0e8"></i></span>Hijau digital</button><button class="theme-preset" type="button" onclick="setTheme(\'#1e3a8a\',\'#fbbf24\',\'#f8fafc\')"><span class="theme-swatches"><i style="background:#1e3a8a"></i><i style="background:#fbbf24"></i><i style="background:#f8fafc"></i></span>Biru tegas</button><button class="theme-preset" type="button" onclick="setTheme(\'#7c2d12\',\'#fb7185\',\'#fff7ed\')"><span class="theme-swatches"><i style="background:#7c2d12"></i><i style="background:#fb7185"></i><i style="background:#fff7ed"></i></span>Hangat kreatif</button></div><div class="form-grid" style="margin-top:16px"><label>Warna utama<input id="theme-primary" name="theme_primary" type="color" value="'.e($primary).'" oninput="previewTheme()"></label><label>Warna tombol<input id="theme-accent" name="theme_accent" type="color" value="'.e($accent).'" oninput="previewTheme()"></label><label>Warna background<input id="theme-background" name="theme_background" type="color" value="'.e($background).'" oninput="previewTheme()"></label></div><p class="muted" style="margin:16px 0 8px">Gaya font judul</p><div class="font-choice"><label style="font-family:Fraunces,serif"><input type="radio" name="theme_font" value="fraunces" '.($font==='fraunces'?'checked':'').'> Editorial modern</label><label style="font-family:Georgia,serif"><input type="radio" name="theme_font" value="serif" '.($font==='serif'?'checked':'').'> Serif klasik</label></div><div class="theme-preview" id="theme-preview" style="background:'.e($background).';color:'.e($primary).'"><strong style="font:26px Fraunces,serif">Preview tampilan toko</strong><p style="margin:8px 0 0">Tombol pembelian memakai warna pilihan Anda.</p><span id="preview-button" style="display:inline-block;margin-top:8px;padding:8px 12px;background:'.e($accent).';color:'.e($primary).'">Beli sekarang</span></div></section><section class="form-section"><h2>Hero ringkas</h2><label>Judul hero<input name="hero_title" value="'.e($s['hero_title']??'').'" placeholder="Produk digital siap kirim"></label><label>Subjudul hero<input name="hero_subtitle" value="'.e($s['hero_subtitle']??'').'" placeholder="Ebook, video, dan akun premium."></label><label>Banner URL HTTPS<input name="hero_banner_url" type="url" placeholder="https://..." value="'.e(str_starts_with($s['hero_banner']??'','http')?$s['hero_banner']:'').'\"></label><label>Atau upload banner<input name="hero_banner_upload" type="file" accept="image/jpeg,image/png,image/webp"></label></section><section class="form-section"><h2>Katalog</h2><label>Judul katalog<input name="catalog_heading" value="'.e($s['catalog_heading']??'Produk pilihan').'\"></label></section><button class="btn lime">Simpan tampilan</button> <a class="btn" href="'.base('/').'" target="_blank">Lihat toko</a></form><script>function setTheme(a,b,c){document.getElementById("theme-primary").value=a;document.getElementById("theme-accent").value=b;document.getElementById("theme-background").value=c;previewTheme()}function previewTheme(){const a=document.getElementById("theme-primary").value,b=document.getElementById("theme-accent").value,c=document.getElementById("theme-background").value;document.getElementById("theme-preview").style.background=c;document.getElementById("theme-preview").style.color=a;const button=document.getElementById("preview-button");button.style.background=b;button.style.color=a}</script>'; }
function product_form_v2(): string { return '<section class="hero"><p class="type">Katalog · produk baru</p><h1>Buat produk.</h1><p class="muted">Pilih cara kirim produk dulu. Form akan menjelaskan data yang diperlukan.</p></section><form method="post"><input type="hidden" name="_csrf" value="'.csrf().'\"><section class="form-section"><h2>Informasi produk</h2><div class="form-grid"><label class="full">Nama produk<input name="name" placeholder="Contoh: Netflix Premium 1 Bulan" required></label><label>Harga (Rupiah)<input name="price" type="number" min="0" placeholder="50000" required></label><label>Foto produk (URL HTTPS)<input name="image_url" type="url" placeholder="https://images.../produk.jpg"></label><label class="full">Deskripsi produk<textarea name="description" placeholder="Jelaskan isi produk, masa aktif, dan informasi penting." required></textarea></label></div><p class="muted">Gunakan URL gambar publik dari CDN, Google Drive direct link, S3/R2, atau hosting gambar lain.</p></section><section class="form-section"><h2>Cara kirim produk</h2><label>Jenis fulfillment<select name="type" id="product-type" onchange="toggleProductFulfillment()"><option value="file_link">File / link digital - ebook, video, template</option><option value="account_stock">Stok akun - Netflix, YouTube Premium, dan lain-lain</option><option value="manual">Manual - admin proses sendiri</option></select></label><div id="file-link-fields"><label>Link produk (HTTPS)<input name="delivery_url" type="url" placeholder="https://drive.google.com/... "></label><p class="muted">Pembeli menerima link ini setelah pembayaran selesai.</p></div><div id="account-stock-fields" hidden><label>Stok awal akun<textarea name="initial_stock" placeholder="email@gmail.com|password\nemail2@gmail.com|password2"></textarea></label><p class="muted">Satu baris adalah satu akun. Format wajib: <strong>email@gmail.com|password</strong>. Sistem mendeteksi dan menyimpan setiap baris sebagai satu stok terenkripsi.</p></div><div id="manual-fields" hidden><p class="muted">Tidak ada pengiriman otomatis. Pesanan lunas masuk ke panel untuk diproses manual.</p></div></section><label><input type="checkbox" name="active" value="1" checked> Produk langsung aktif di katalog</label><button class="btn lime">Buat produk</button></form><script>function toggleProductFulfillment(){const type=document.getElementById("product-type").value;document.getElementById("file-link-fields").hidden=type!=="file_link";document.getElementById("account-stock-fields").hidden=type!=="account_stock";document.getElementById("manual-fields").hidden=type!=="manual"}toggleProductFulfillment()</script>'; }
function settings_page_v2(array $s): string { return '<section class="hero"><p class="type">Gateway dan email</p><h1>Pengaturan.</h1><p class="muted">Simpan perubahan sebelum menjalankan test SMTP.</p></section><div class="page-actions"><span class="status '.e($s['pakasir_mode']??'sandbox').'">Pakasir '.e(ucfirst($s['pakasir_mode']??'sandbox')).'</span><button class="btn" type="button" onclick="document.getElementById(\'smtp-test-modal\').showModal()">Test SMTP</button></div><section class="panel"><form method="post"><input type="hidden" name="_csrf" value="'.csrf().'\"><h2>Pakasir</h2>'.pakasir_mode_field($s).'<label>Project slug Pakasir<input name="pakasir_slug" value="'.e($s['pakasir_slug']??'').'" autocomplete="off"></label><label>API key Pakasir<input name="pakasir_api_key" type="password" placeholder="Kosongkan untuk tidak mengubah" autocomplete="new-password"></label><label><input type="checkbox" name="qris_only" value="1" '.(($s['pakasir_qris_only']??'')==='1'?'checked':'').'> Hanya QRIS</label><h2>SMTP</h2><label>SMTP host<input name="smtp_host" value="'.e($s['smtp_host']??'').'" autocomplete="off"></label><label>SMTP port<input name="smtp_port" type="number" min="1" max="65535" value="'.e($s['smtp_port']??'587').'\"></label><label>SMTP username<input name="smtp_user" value="'.e($s['smtp_user']??'').'" autocomplete="off"></label><label>SMTP password<input name="smtp_pass" type="password" placeholder="Kosongkan untuk tidak mengubah" autocomplete="new-password"></label><label>Email pengirim<input name="smtp_from" type="email" value="'.e($s['smtp_from']??'').'" autocomplete="off"></label><label>Nama pengirim<input name="smtp_name" value="'.e($s['smtp_name']??'').'" autocomplete="off"></label><p class="muted">Set webhook Pakasir ke '.e(absolute_url('/webhooks/pakasir')).'.</p><button>Simpan pengaturan</button></form></section><dialog class="modal" id="smtp-test-modal"><div class="modal-card"><p class="type">Kirim email test</p><h2>Periksa SMTP.</h2><p class="muted">Email akan dikirim lewat konfigurasi SMTP yang sudah tersimpan.</p><form method="post" action="'.base('/admin/settings/test-smtp').'" ><input type="hidden" name="_csrf" value="'.csrf().'\"><label>Email tujuan<input name="test_email" type="email" placeholder="nama@email.com" required autofocus></label><div class="page-actions" style="margin:4px 0 0"><button type="button" onclick="document.getElementById(\'smtp-test-modal\').close()">Batal</button><button class="btn lime">Kirim test</button></div></form></div></dialog>'; }
function settings_page(array $s): string { return '<section class="hero"><p class="type">Gateway dan email</p><h1>Pengaturan.</h1><p class="muted">Simpan perubahan sebelum menjalankan test SMTP.</p></section><div class="page-actions"><span class="muted">Koneksi dan pengiriman</span><button class="btn" type="button" onclick="document.getElementById(\'smtp-test-modal\').showModal()">Test SMTP</button></div><section class="panel"><form method="post"><input type="hidden" name="_csrf" value="'.csrf().'"><h2>Pakasir</h2><label>Project slug Pakasir<input name="pakasir_slug" value="'.e($s['pakasir_slug']??'').'" autocomplete="off"></label><label>API key Pakasir<input name="pakasir_api_key" type="password" placeholder="Kosongkan untuk tidak mengubah" autocomplete="new-password"></label><label><input type="checkbox" name="qris_only" value="1" '.(($s['pakasir_qris_only']??'')==='1'?'checked':'').'> Hanya QRIS</label><h2>SMTP</h2><label>SMTP host<input name="smtp_host" value="'.e($s['smtp_host']??'').'" autocomplete="off"></label><label>SMTP port<input name="smtp_port" type="number" min="1" max="65535" value="'.e($s['smtp_port']??'587').'"></label><label>SMTP username<input name="smtp_user" value="'.e($s['smtp_user']??'').'" autocomplete="off"></label><label>SMTP password<input name="smtp_pass" type="password" placeholder="Kosongkan untuk tidak mengubah" autocomplete="new-password"></label><label>Email pengirim<input name="smtp_from" type="email" value="'.e($s['smtp_from']??'').'" autocomplete="off"></label><label>Nama pengirim<input name="smtp_name" value="'.e($s['smtp_name']??'').'" autocomplete="off"></label><p class="muted">Set webhook Pakasir ke '.e(absolute_url('/webhooks/pakasir')).'.</p><button>Simpan pengaturan</button></form></section><dialog class="modal" id="smtp-test-modal"><div class="modal-card"><p class="type">Kirim email test</p><h2>Periksa SMTP.</h2><p class="muted">Email akan dikirim lewat konfigurasi SMTP yang sudah tersimpan.</p><form method="post" action="'.base('/admin/settings/test-smtp').'" ><input type="hidden" name="_csrf" value="'.csrf().'"><label>Email tujuan<input name="test_email" type="email" placeholder="nama@email.com" required autofocus></label><div class="page-actions" style="margin:4px 0 0"><button type="button" onclick="document.getElementById(\'smtp-test-modal\').close()">Batal</button><button class="btn lime">Kirim test</button></div></form></div></dialog>'; }
function send_smtp_test(string $to): void { $s=q('SELECT `key`,value FROM settings WHERE `key` LIKE "smtp_%"')->fetchAll(PDO::FETCH_KEY_PAIR);if(empty($s['smtp_host'])||empty($s['smtp_from']))throw new RuntimeException('Simpan host SMTP dan email pengirim terlebih dahulu.');$autoload=ROOT.'/vendor/autoload.php';if(!is_file($autoload))throw new RuntimeException('Dependency PHPMailer tidak ditemukan.');require_once $autoload;$mail=new PHPMailer\PHPMailer\PHPMailer(true);$mail->isSMTP();$mail->Host=$s['smtp_host'];$mail->Port=(int)($s['smtp_port']?:587);$mail->SMTPAuth=!empty($s['smtp_user']);$mail->Username=$s['smtp_user']??'';$mail->Password=$s['smtp_pass']??'';$mail->SMTPSecure=PHPMailer\PHPMailer\PHPMailer::ENCRYPTION_STARTTLS;$mail->SMTPAutoTLS=true;$mail->Timeout=15;$mail->CharSet='UTF-8';$mail->setFrom($s['smtp_from'],$s['smtp_name']?:'Toko Digital');$mail->addAddress($to);$mail->Subject='Test SMTP berhasil';$mail->Body='Koneksi SMTP untuk toko digital berhasil dikonfigurasi pada '.date('d M Y H:i').'.';$mail->send(); }
function product_form(?array $p=null,string $action=''): string { $p??=['name'=>'','type'=>'file_link','description'=>'','price'=>'','delivery_url'=>'','active'=>1];return '<h2>'.($action?'Ubah produk':'Produk baru').'</h2><form method="post" action="'.base($action).'" ><input type="hidden" name="_csrf" value="'.csrf().'"><label>Nama produk<input name="name" value="'.e($p['name']).'" required></label><label>Tipe<select name="type"><option value="file_link" '.($p['type']==='file_link'?'selected':'').'>File / link digital</option><option value="account_stock" '.($p['type']==='account_stock'?'selected':'').'>Stok akun</option><option value="manual" '.($p['type']==='manual'?'selected':'').'>Manual</option></select></label><label>Deskripsi<textarea name="description" required>'.e($p['description']).'</textarea></label><label>Harga Rupiah<input name="price" type="number" min="0" value="'.e((string)$p['price']).'" required></label><label>Link pengiriman file/video<input name="delivery_url" type="url" value="'.e($p['delivery_url']).'" placeholder="https://drive.google.com/... "></label><p class="muted">Untuk ebook/video, isi link Google Drive, S3, R2, atau URL digital lain. Link terkirim setelah lunas.</p><label><input type="checkbox" name="active" value="1" '.($p['active']?'checked':'').'> Produk aktif</label><button>Simpan produk</button></form>'; }
function fulfill_order(array $order): void { if($order['status']!=='pending')return; db()->beginTransaction(); try { $item=q('SELECT * FROM order_items WHERE order_id=? FOR UPDATE',[$order['id']])->fetch(); $message="Terima kasih. Pesanan {$order['invoice']} sudah dibayar.\n\n"; if($item['product_type']==='account_stock'){ $stock=q("SELECT * FROM stock_items WHERE product_id=? AND status='available' ORDER BY id LIMIT 1 FOR UPDATE",[$item['product_id']])->fetch(); if(!$stock)throw new RuntimeException('Stok habis saat fulfillment'); q("UPDATE stock_items SET status='sold',order_item_id=?,sold_at=NOW() WHERE id=?",[$item['id'],$stock['id']]); $message.="Detail akun:\n".decrypt_stock($stock['payload']); } elseif($item['product_type']==='file_link'){ $message.="Link produk:\n".$item['delivery_url']; } else { $message.="Pesanan diterima. Admin akan memproses produk Anda."; } q("UPDATE order_items SET delivered_at=NOW() WHERE id=?",[$item['id']]); q("UPDATE orders SET status='fulfilled',paid_at=NOW() WHERE id=?",[$order['id']]); db()->commit(); send_mail($order['buyer_email'],'Pesanan '.$order['invoice'].' berhasil',$message); } catch(Throwable $e) { if(db()->inTransaction())db()->rollBack(); throw $e; } }
function send_mail(string $to,string $subject,string $message): void { $s=q('SELECT `key`,value FROM settings WHERE `key` LIKE "smtp_%"')->fetchAll(PDO::FETCH_KEY_PAIR); $autoload=ROOT.'/vendor/autoload.php'; if(is_file($autoload) && !empty($s['smtp_host'])) { require_once $autoload; $mail=new PHPMailer\PHPMailer\PHPMailer(true); $mail->isSMTP();$mail->Host=$s['smtp_host'];$mail->Port=(int)($s['smtp_port']?:587);$mail->SMTPAuth=true;$mail->Username=$s['smtp_user'];$mail->Password=$s['smtp_pass'];$mail->SMTPSecure=PHPMailer\PHPMailer\PHPMailer::ENCRYPTION_STARTTLS;$mail->CharSet='UTF-8';$mail->setFrom($s['smtp_from'],$s['smtp_name']?:'Toko Digital');$mail->addAddress($to);$mail->Subject=$subject;$mail->Body=$message;$mail->send();return; } @mail($to,$subject,$message,"Content-Type: text/plain; charset=UTF-8\r\n"); }
